mapper.select:
SELECT id, spu_code, spu_name, category_code, brand, base_unit, status, deleted, created_at, updated_at, created_by, updated_by FROM spu WHERE deleted = 0
AND (spu_name LIKE CONCAT('%', #{keyword}, '%') OR spu_code LIKE CONCAT('%', #{keyword}, '%'))
AND category_code = #{categoryCode}
AND status = #{status}
ORDER BY created_at DESC, id DESC
